20              v-model:selected=&#34;table.selected&#34;
21              v-if=&#34;opt.parent_id == 0&#34;&gt;
22        &lt;template v-slot:default-header=&#34;prop&#34;&gt;
23          &lt;div class=&#34;items-center&#34;&gt;
24            {{ prop.node.desc }}({{ prop.node.name }})
25          &lt;/div&gt;
