14        w bytes.Buffer
15        z = html.NewTokenizer(bytes.NewReader(d))
16    )
17    for {
18        next := z.Next()
19        if next == html.ErrorToken {
20            break
21        }
22
23        token := z.Token()
24        switch next {
25        case html.StartTagToken, html.SelfClosingTagToken:
26            // 找到shortcode标签
