    然后根据标签参数替换原来的HTML

 1// 获取该标签的参数
 2attrs := make(map[string]string)
 3for _, attr := range token.Attr {
 4    attrs[attr.Key] = attr.Val
 5}
 6// 确认是163music
 7if attrs[&#34;_name&#34;] == &#34;163music&#34; {
 8    // 获取替换的内容
 9    var buf bytes.Buffer
10    err := tmpl.Execute(&amp;buf, attrs)
11    if err != nil {
12        panic(err)
13    }
14    w.WriteString(buf.String())
15    continue
16}


