185                self.write_message(&#39;file is too large!&#39;)
186            else:
187                with open(out_file, &#39;r&#39;) as f:
188                    f.seek(0, os.SEEK_END)
189                    fsize = f.tell()
190                    f.seek(max(fsize - 1024, 0), 0)
191                    for line in f.readlines()[-800:]:
192                        self.write_message(&#39;{}:{}&#39;.format(message[&#39;msg&#39;],
193                                                          line))
194
